import{_ as a,o as r,c as t,a3 as n}from"./chunks/framework.CjquFG0V.js";const b=JSON.parse('{"title":"42. Meal Breaks","description":"","frontmatter":{"title":"42. Meal Breaks","eba":"Biomedical Engineers 2025-2028","topics":["hours","shift-work","breaks","on-call"]},"headers":[],"relativePath":"ebas/biomedical-engineers/hours-of-work/42-meal-breaks.md","filePath":"ebas/biomedical-engineers/hours-of-work/42-meal-breaks.md"}'),o={name:"ebas/biomedical-engineers/hours-of-work/42-meal-breaks.md"};function s(i,e,l,m,d,c){return r(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="_42-meal-breaks" tabindex="-1">42. Meal Breaks <a class="header-anchor" href="#_42-meal-breaks" aria-label="Permalink to &quot;42. Meal Breaks&quot;">​</a></h1><p><strong>42.1</strong> A meal break of not less than 30 minutes and not more than 60 minutes shall be allowed during each shift in excess of five hours and shall not be counted as time worked.</p><p><strong>42.2</strong> Crib time</p><p><strong>(a)</strong> Where Employees are regularly unable to take their meal breaks (including because they are not relieved from duty (and on-call)), a ‘crib time’ arrangement will operate. The crib time arrangement entitles an Employee to a paid meal break of not less than 20 minutes to commence between three and five hours of duty.</p><p><strong>(b)</strong> The above crib time arrangement may also be adopted in any case where there is mutual agreement between the Employer and the Employee.</p><p><strong>42.3</strong> Mandatory training</p><p>Except where it is not reasonably practicable, mandatory in-house training and/or in- house professional development will not be conducted during an Employee’s meal break.</p>',7)])])}const h=a(o,[["render",s]]);export{b as __pageData,h as default};
